//=============================================================================
// Grid Slot
//=============================================================================

LOGICPULSE.UI.GridSlot = class extends LOGICPULSE.UI.Element {

    constructor(options = {}) {

        super();

        this._entry = options.entry || null;

        this.move(

            options.x ?? 0,
            options.y ?? 0

        );

        this.create();

    }

    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createBackground();

        this.createIcon();

    }

    //--------------------------------
    // Refresh
    //--------------------------------

    refresh() {

        this.removeChildren();

        this.create();

    }

    //--------------------------------
    // Background
    //--------------------------------

    createBackground() {

        const image = this.getBackgroundImage();

        this._background = this.createSprite(

            LOGICPULSE.Assets.Folders.Inventory,
            image

        );

    }

    //--------------------------------
    // Icon
    //--------------------------------

    createIcon() {

        const item = this.item();

        if (!item) {

            return;

        }

        this._icon = LOGICPULSE.Assets.createItemSprite(

            item

        );

        const offset =

            LOGICPULSE.Layout.Inventory.Grid.Icon.offset;

        this._icon.x = offset.x;
        this._icon.y = offset.y;

        this.addChild(this._icon);

    }

    //--------------------------------
    // Center Icon
    //--------------------------------

    centerIcon() {

        const slotSize = 92;

        const iconWidth = ImageManager.iconWidth;

        const iconHeight = ImageManager.iconHeight;

        this._icon.x = Math.floor(

            (slotSize - iconWidth) / 2

        );

        this._icon.y = Math.floor(

            (slotSize - iconHeight) / 2

        );

    }

    //--------------------------------
    // Background Image
    //--------------------------------

    getBackgroundImage() {

        switch (this.rarity()) {

            case 3:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxLegendary;

            case 2:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxRare;

            default:

                return LOGICPULSE.Assets.Images.Inventory.ItemBoxCommon;

        }

    }

    //--------------------------------
    // Entry
    //--------------------------------

    entry() {

        return this._entry;

    }

    //--------------------------------
    // Item
    //--------------------------------

    item() {

        return this._entry?.item ?? null;

    }

    //--------------------------------
    // Amount
    //--------------------------------

    amount() {

        return this._entry?.amount ?? 0;

    }

    //--------------------------------
    // Rarity
    //--------------------------------

    rarity() {

        return this._entry?.rarity ?? 1;

    }

    //--------------------------------
    // Category
    //--------------------------------

    category() {

        return this._entry?.category ?? null;

    }

};


//=============================================================================
// LPGrid.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};

//=============================================================================
// Grid
//=============================================================================

LOGICPULSE.UI.Grid = class extends LOGICPULSE.UI.Element {

    constructor(layout) {

        super();

        this._layout = layout;

        this._category =

            LOGICPULSE.Constants.Category.Consumable;

        this.create();

    }

    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createMask();
        this.createViewport();

    }

    //--------------------------------
    // Mask
    //--------------------------------

    createMask() {

        const mask = this._layout.mask;

        this._maskGraphic = new PIXI.Graphics();

        this._maskGraphic.beginFill(0xffffff);

        this._maskGraphic.drawRect(

            mask.x,
            mask.y,
            mask.width,
            mask.height

        );

        this._maskGraphic.endFill();

        this.addChild(this._maskGraphic);

        this.mask = this._maskGraphic;

    }

    //--------------------------------
    // Viewport
    //--------------------------------

    createViewport() {

        this._viewport = new PIXI.Container();

        this.addChild(this._viewport);

        this.createLayers();

    }

    //--------------------------------
    // Layers
    //--------------------------------

    createLayers() {

        this._slotLayer = new PIXI.Container();
        this._iconLayer = new PIXI.Container();
        this._cursorLayer = new PIXI.Container();

        this._viewport.addChild(this._slotLayer);
        this._viewport.addChild(this._iconLayer);
        this._viewport.addChild(this._cursorLayer);

        this.buildGrid();

    }

    //--------------------------------
    // Grid
    //--------------------------------

    buildGrid() {

        this.clearSlots();
        this.buildSlots();

    }

    //--------------------------------
    // Clear Slots
    //--------------------------------

    clearSlots() {

        this._slotLayer.removeChildren();

    }

    //--------------------------------
    // Build Slots
    //--------------------------------

    buildSlots() {

        const items = this.items();

        for (let index = 0; index < items.length; index++) {

            const position = this.slotPosition(index);

            const entry = items[index];

            const slot = new LOGICPULSE.UI.GridSlot({

                x: position.x,

                y: position.y,

                entry: entry

            });

            this._slotLayer.addChild(slot);

        }

    }

    //--------------------------------
    // Slot Position
    //--------------------------------

    slotPosition(index) {

        const layout = this._layout;

        return {

            x:

                layout.rect.x +
                ((index % layout.columns) * layout.spacingX),

            y:

                layout.rect.y +
                (Math.floor(index / layout.columns) * layout.spacingY)

        };

    }

    //--------------------------------
    // Set Category
    //--------------------------------

    setCategory(category) {

        if (this._category === category) {

            return;

        }

        this._category = category;

        this.buildGrid();

    }

    //--------------------------------
    // Category
    //--------------------------------

    category() {

        return this._category;

    }

    //--------------------------------
    // Items
    //--------------------------------

    items() {

        return LOGICPULSE.InventoryProvider.getItems(

            this._category

        );

    }

};


